export function getTotalPages(): number {
  return MODULES.reduce((acc, m) => acc + m.pages.length, 0)
}

export function getModuleById(id: string): CourseModule | undefined {
  return MODULES.find(m => m.id === id)
}

export function getPageById(moduleId: string, pageId: string): CoursePage | undefined {
  return getModuleById(moduleId)?.pages.find(p => p.id === pageId)
}

export function getNextPage(moduleId: string, pageId: string): { moduleId: string; pageId: string } | null {
  const modIdx = MODULES.findIndex(m => m.id === moduleId)
  if (modIdx === -1) return null
  const mod = MODULES[modIdx]
  const pageIdx = mod.pages.findIndex(p => p.id === pageId)
  if (pageIdx < mod.pages.length - 1) {
    return { moduleId, pageId: mod.pages[pageIdx + 1].id }
  }
  if (modIdx < MODULES.length - 1) {
    return { moduleId: MODULES[modIdx + 1].id, pageId: MODULES[modIdx + 1].pages[0].id }
  }
  return null
}

export function getPrevPage(moduleId: string, pageId: string): { moduleId: string; pageId: string } | null {
  const modIdx = MODULES.findIndex(m => m.id === moduleId)
  if (modIdx === -1) return null
  const mod = MODULES[modIdx]
  const pageIdx = mod.pages.findIndex(p => p.id === pageId)
  if (pageIdx > 0) {
    return { moduleId, pageId: mod.pages[pageIdx - 1].id }
  }
  if (modIdx > 0) {
    const prevMod = MODULES[modIdx - 1]
    return { moduleId: prevMod.id, pageId: prevMod.pages[prevMod.pages.length - 1].id }
  }
  return null
}
